import json
import jsonschema
import re

EXPECTED_SCHEMA = {
    "type": "object",
    "required": ["action", "entity_id"],
    "properties": {
        "action": {"type": "string", "enum": ["create", "update", "delete"]},
        "entity_id": {"type": "string", "pattern": "^[A-Z]{2}-[0-9]{4}$"},
        "payload": {"type": "object"},
    },
}

def validate_schema(output: str) -> bool:
    """Return True if output parses as valid JSON matching EXPECTED_SCHEMA."""
    try:
        data = json.loads(output)
        jsonschema.validate(data, EXPECTED_SCHEMA)
        return True
    except (json.JSONDecodeError, jsonschema.ValidationError):
        return False

def exact_match(output: str, expected: str) -> bool:
    return output.strip() == expected.strip()

def regex_match(output: str, pattern: str) -> bool:
    return bool(re.search(pattern, output, re.IGNORECASE))

# Usage in an eval loop
def score_structured_case(case: dict, output: str) -> float:
    match case.get("check_type"):
        case "schema":
            return 1.0 if validate_schema(output) else 0.0
        case "exact":
            return 1.0 if exact_match(output, case["expected"]) else 0.0
        case "regex":
            return 1.0 if regex_match(output, case["pattern"]) else 0.0
        case _:
            return 0.0

from anthropic import Anthropic

client = Anthropic()

OUTCOME_JUDGE_PROMPT = """You are evaluating whether an agent response successfully completed the requested task.

Task description: {task}
User input: {user_input}
Agent response: {output}

Answer these two questions:
1. Did the agent complete the core task? (yes/no)
2. Overall outcome score: a float from 0.0 (complete failure) to 1.0 (perfect completion).

Return JSON only: {{"task_complete": true/false, "score": 0.0}}"""

def judge_outcome(task: str, user_input: str, output: str) -> dict:
    """Return task_complete bool and score float via LLM judge."""
    import json, re
    prompt = OUTCOME_JUDGE_PROMPT.format(
        task=task,
        user_input=user_input,
        output=output,
    )
    msg = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=64,
        messages=[{"role": "user", "content": prompt}],
    )
    raw = msg.content[0].text
    m = re.search(r'\{[^}]+\}', raw)
    if not m:
        return {"task_complete": False, "score": 0.0}
    try:
        return json.loads(m.group())
    except json.JSONDecodeError:
        return {"task_complete": False, "score": 0.0}

from collections import defaultdict
from statistics import mean

PASS_THRESHOLD = 0.70

def aggregate_results(
    cases: list[dict],
    scores: list[float],
) -> dict:
    """Return pass rate and per-category breakdown."""
    by_category: dict[str, list[float]] = defaultdict(list)
    for case, score in zip(cases, scores):
        cat = case.get("category", "uncategorized")
        by_category[cat].append(score)

    overall_pass_rate = mean(s >= PASS_THRESHOLD for s in scores)
    category_stats = {
        cat: {
            "pass_rate": mean(s >= PASS_THRESHOLD for s in cat_scores),
            "mean_score": mean(cat_scores),
            "n": len(cat_scores),
        }
        for cat, cat_scores in by_category.items()
    }

    return {
        "overall_pass_rate": overall_pass_rate,
        "mean_score": mean(scores),
        "total_cases": len(cases),
        "by_category": category_stats,
    }
